   112→void expectRight<T>(Result<Failure, T> response) {
   113→  expect(response.hasLeft, false,
   114→      reason: response.hasLeft
   115→          ? '${response.left.toString()}\n${response.left.underlyingException}'
   116→          : null);
   117→  expect(response.hasRight, true);
   118→}
