   120→List<Session> _createExpectedSessionList({
   121→  String? teamId,
   122→  String? userId,
   123→  String? playerId,
   124→  DateTime? startDate,
   125→  DateTime? endDate,
   126→}) {
   127→  return sessionRecords.data
   128→      .where((session) =>
   129→          !session.deleteFlag! &&
   130→          (teamId != null ? session.teamId == teamId : true) &&
   131→          (userId != null ? session.userId == userId : true) &&
   132→          (playerId != null ? session.playerId == playerId : true) &&
   133→          (startDate != null
   134→              ? session.createdAt != null
   135→                  ? session.createdAt!.compareTo(startDate) >= 0
   136→                  : false
   137→              : true) &&
   138→          (endDate != null
   139→              ? session.createdAt != null
   140→                  ? session.createdAt!.compareTo(endDate) <= 0
   141→                  : false
   142→              : true))
   143→      .sortedByCompare((session) => session.createdAt,
   144→          (a, b) => a == null || b == null ? 0 : b.compareTo(a))
   145→      .map((session) => session)
   146→      .toList();
   147→}
   148→
   149→Session _findExpectedSessionById(String sessionId) {
   150→  return sessionRecords.data.where((session) => session.id == sessionId).first;
