   169→          resource.sessionId == sessionId && !resource.deleteFlag!)
   170→      .sortedByCompare(
   171→          (resource) => resource.createdAt!, (a, b) => b.compareTo(a))
   172→      .toList();
   173→}
   174→
   175→ResourceData _createExpectedResourceDetail(String resourceId) {
   176→  final resource =
