   198→List<BallInfo> _createExpectedBallInfoList(
   199→  ResourceData resource,
   200→) {
   201→  // This mimics api server logic
   202→  final balls = Map.fromEntries(ballRecords.data
   203→      .where((ball) =>
   204→          ball.resourceId == resource.id &&
   205→          ((ball.isPitched ?? false) || (ball.isHit ?? false)))
   206→      .sortedBy<num>((ball) => ball.id!)
   207→      .map((ball) => MapEntry(ball.ballIndex!, ball)));
   208→  final ballPositions = ballPositionRecords.data
   209→      .where((ballPosition) => ballPosition.resourceId == resource.id)
   210→      .sortedBy<num>((ballPosition) => ballPosition.id!)
   211→      .groupListsBy((ballPosition) => ballPosition.ballIndex!);
   212→  final ballInfoListExpected = balls.entries
   213→      .map(
   214→        (ballEntry) => BallInfo(
   215→          ball: ballEntry.value,
   216→          positions: ballPositions[ballEntry.key] ?? [],
   217→        ),
   218→      )
   219→      .toList();
   220→
   221→  return ballInfoListExpected;
   222→}
