   224→void _expectList<T, U>(
   225→    List<T> actual, List<U> expected, Function(T, U) comparator) {
   226→  expect(
   227→    actual.length,
   228→    expected.length,
   229→    reason:
   230→        'list length does not match: (actual: ${actual.length}, expected: ${expected.length})',
   231→  );
   232→  for (var i = 0; i < actual.length; i++) {
   233→    comparator(actual[i], expected[i]);
   234→  }
   235→}
