   451→void _expectMap<K, V1, V2>(
   452→    Map<K, V1> actual, Map<K, V2> expected, void Function(V1, V2) validator) {
   453→  expect(actual.keys.length, expected.keys.length);
   454→  for (final expectedEntry in expected.entries) {
   455→    expect(actual.containsKey(expectedEntry.key), true);
   456→    final actualValue = actual[expectedEntry.key];
   457→    if (actualValue != null) {
   458→      validator(actualValue, expectedEntry.value);
   459→    }
   460→  }
   461→}
