import 'create_accessible_contents.dart';

void expectSessions(
  List<Session> actual, {
  String? teamId,
  String? userId,
  String? playerId,
  DateTime? startDate,
  DateTime? endDate,
}) {
  final expected = _createExpectedSessionList(
    teamId: teamId,
    userId: userId,
    playerId: playerId,
    startDate: startDate,
    endDate: endDate,
  );
  _expectList(actual, expected, _expectSession);
}

void expectSessionById(Session actual, String sessionId) {
  final expected = _findExpectedSessionById(sessionId);
  _expectSession(actual, expected);
}

void expectPlayers(
  List<Player> actual, {
  String? teamId,
  String? userId,
}) {
  final expected = _createExpectedPlayerList(teamId: teamId, userId: userId);
  _expectList(actual, expected, _expectPlayer);
}

void expectResourcesBySessionId(List<ResourceData> actual, String sessionId) {
  final expected = _createExpectedResourceList(sessionId);
  _expectList(actual, expected, _expectResource);
}

void expectResourceBySessionId(List<ResourceData> actual, String sessionId) {
  final expected = _createExpectedResourceList(sessionId)
      .map((session) => session.id!)
      .toList();
  _expectList(actual, expected, expect);
}

void expectResourceDetailById(ResourceData actual, String resourceId) {
  final expected = _createExpectedResourceDetail(resourceId);
  _expectResourceDetail(actual, expected);
}

void expectTeamById(Team actual, String teamId) {
  final expected = _findTeamById(teamId);
  _expectTeam(actual, expected);
}

void expectUserInfoByUserId(UserInfo actual, String userId) {
  final expected = _findUserDataById(userId);
  _expectUserInfoFromUserData(actual, expected);
}

void expectTeamMemberProfilesByTeamId(List<Profile> actual, String teamId) {
  final expected = _createUserDataListByTeamId(teamId);
  _expectList(actual, expected, _expectProfileFromUserData);
