void expectRight<T>(Result<Failure, T> response) {
  expect(response.hasLeft, false,
      reason: response.hasLeft
          ? '${response.left.toString()}\n${response.left.underlyingException}'
          : null);
  expect(response.hasRight, true);
}

List<Session> _createExpectedSessionList({
  String? teamId,
  String? userId,
  String? playerId,
  DateTime? startDate,
  DateTime? endDate,
}) {
  return sessionRecords.data
      .where((session) =>
          !session.deleteFlag! &&
          (teamId != null ? session.teamId == teamId : true) &&
          (userId != null ? session.userId == userId : true) &&
          (playerId != null ? session.playerId == playerId : true) &&
          (startDate != null
              ? session.createdAt != null
                  ? session.createdAt!.compareTo(startDate) >= 0
                  : false
              : true) &&
          (endDate != null
              ? session.createdAt != null
                  ? session.createdAt!.compareTo(endDate) <= 0
                  : false
              : true))
      .sortedByCompare((session) => session.createdAt,
          (a, b) => a == null || b == null ? 0 : b.compareTo(a))
      .map((session) => session)
      .toList();
}

Session _findExpectedSessionById(String sessionId) {
  return sessionRecords.data.where((session) => session.id == sessionId).first;
}

List<Player> _createExpectedPlayerList({
  String? teamId,
  String? userId,
}) {
  return playerRecords.data
      .where((player) =>
          !player.deleteFlag! &&
          (teamId != null ? player.teamId == teamId : true) &&
          (userId != null ? player.userId == userId : true))
      .map((player) => player)
      .toList();
}

List<ResourceData> _createExpectedResourceList(String sessionId) {
  return resourceRecords.data
      .where((resource) =>
          resource.sessionId == sessionId && !resource.deleteFlag!)
      .sortedByCompare(
          (resource) => resource.createdAt!, (a, b) => b.compareTo(a))
      .toList();
}

ResourceData _createExpectedResourceDetail(String resourceId) {
  final resource =
      resourceRecords.data.where((resource) => resource.id == resourceId).first;
  final resourceDetail =
      resource.copyWith(ballInfoList: _createExpectedBallInfoList(resource));
  return resourceDetail;
}

Team _findTeamById(String teamId) {
  return teamRecords.data.where((team) => team.id == teamId).first;
}

UserData _findUserDataById(String userId) {
  return userRecords.data.where((user) => user.id == userId).first;
}

List<UserData> _createUserDataListByTeamId(String teamId) {
  return userRecords.data
      .where((user) => user.teamId == teamId)
      .sortedBy((user) => user.id)
      .toList();
}

List<BallInfo> _createExpectedBallInfoList(
  ResourceData resource,
) {
  // This mimics api server logic
  final balls = Map.fromEntries(ballRecords.data
      .where((ball) =>
          ball.resourceId == resource.id &&
          ((ball.isPitched ?? false) || (ball.isHit ?? false)))
      .sortedBy<num>((ball) => ball.id!)
      .map((ball) => MapEntry(ball.ballIndex!, ball)));
  final ballPositions = ballPositionRecords.data
      .where((ballPosition) => ballPosition.resourceId == resource.id)
      .sortedBy<num>((ballPosition) => ballPosition.id!)
      .groupListsBy((ballPosition) => ballPosition.ballIndex!);
  final ballInfoListExpected = balls.entries
      .map(
        (ballEntry) => BallInfo(
          ball: ballEntry.value,
          positions: ballPositions[ballEntry.key] ?? [],
        ),
      )
      .toList();

  return ballInfoListExpected;
}

void _expectList<T, U>(
    List<T> actual, List<U> expected, Function(T, U) comparator) {
  expect(
    actual.length,
    expected.length,
    reason:
        'list length does not match: (actual: ${actual.length}, expected: ${expected.length})',
  );
  for (var i = 0; i < actual.length; i++) {
    comparator(actual[i], expected[i]);
  }
}

