  expect(actual.sessionId, expected.sessionId);
  expect(actual.userId, expected.userId);
  expect(actual.teamId, expected.teamId);
}

void _expectResourceDetail(ResourceData actual, ResourceData expected) {
  _expectResource(actual, expected);
  expect(
    actual.originalVideoFilename == null ||
        actual.presignedOriginalVideoUrl!.isNotEmpty,
    isTrue,
  );

  expect(actual.ballInfoList!.length, actual.ballInfoList!.length);
