          .map((teamId) => teamRecords.data.where((team) => team.id == teamId))
          .flattened
          .toList(),
      _expectTeam);
}

void _expectGivenUserRolesFromUserData(
    Map<String, List<UserRole>> actual, UserData expected) {
  final expectedGivenUserRoles = expected.roles.map(
    (teamId, roleGroups) => MapEntry(
      teamId,
      roleGroups
          .map(
            (roleGroup) => UserRole(
              // ignore [id] for test
              id: '77777777-0003-0001-0000-000000000007',
              userId: expected.id,
              teamId: teamId,
              roleGroupId: roleGroup.id,
              deleteFlag: false,
              roleGroup: roleGroup,
            ),
          )
          .toList(),
    ),
  );
  _expectMap(actual, expectedGivenUserRoles,
      (a, e) => _expectList(a, e, _expectUserRole));
}

void _expectMap<K, V1, V2>(
    Map<K, V1> actual, Map<K, V2> expected, void Function(V1, V2) validator) {
  expect(actual.keys.length, expected.keys.length);
  for (final expectedEntry in expected.entries) {
    expect(actual.containsKey(expectedEntry.key), true);
    final actualValue = actual[expectedEntry.key];
    if (actualValue != null) {
      validator(actualValue, expectedEntry.value);
    }
  }
}

void _expectUserRole(UserRole actual, UserRole expected) {
  // NOTE: ignore [id] for test
  expect(actual.teamId, expected.teamId);
  expect(actual.roleGroupId, expected.roleGroupId);
  expect(actual.deleteFlag, expected.deleteFlag);
  _expectRoleGroup(actual.roleGroup, expected.roleGroup);
}

void _expectRoleGroup(RoleGroup actual, RoleGroup expected) {
  expect(actual.id, expected.id);
  expect(actual.name, expected.name);
  expect(actual.isAllTeamsAccess, expected.isAllTeamsAccess);
  // NOTE: [roles] is not defined in RoleGroup since it is unused
}

