        (userData) => userData.roles.entries.map(
          (roleEntry) => roleEntry.value.map(
            (roleGroup) => (
              userId: userData.id,
              teamId: roleEntry.key,
              roleGroup: roleGroup,
            ),
          ),
        ),
      )
      .flattened
      .flattened
      .toList(),
  columns: {
    'id': (e) => e.userId,
    'user_id': (e) => e.userId,
    'team_id': (e) => e.teamId,
    'role': (e) => e.roleGroup.name.toJson(),
    'role_group_id': (e) => e.roleGroup.id,
    'created_at': (_) => _time,
    'updated_at': (_) => _time,
  },
);
